#' Create a torch device specification
#'
#' @param type Device type string ("cpu" or "cuda").
#' @param index Device index (default 0).
#' @return A device string.
#' @export
#' @examples
#' \donttest{
#' if (torch_is_installed()) {
#' 
#' # Via string
#' torch_device("cuda:1")
#' torch_device("cpu")
#' torch_device("cuda") # current cuda device
#' 
#' # Via string and device ordinal
#' torch_device("cuda", 0)
#' torch_device("cpu", 0)
#' }
