# ---- Final 6 gaps ----

#' Orthogonal initialization
#'
#' @param tensor A 2D+ tensor.
#' @param gain Scaling factor. Default 1.
#' @return tensor (modified in place).
#' @export
#' @examples
#' \donttest{
#' if (torch_is_installed()) {
#' w <- torch_empty(3, 5)
#' nn_init_orthogonal_(w)
#' }
#' }
nn_init_orthogonal_ <- function(tensor, gain = 1) {
  dims <- tensor$size()
  rows <- dims[1]
  cols <- prod(dims[-1])
  flat <- torch_randn(c(rows, cols))
  # QR decomposition for orthogonal matrix
  qr_result <- torch_linalg_qr(flat)
  q <- qr_result[[1]]
  r <- qr_result[[2]]
  # Fix sign to make deterministic
  d <- torch_diag(r)
  ph <- torch_sign(d)
  q <- q * ph$unsqueeze(1L)
  if (rows < cols) q <- q$t()
  with_no_grad(function() {
    tensor$view(c(rows, cols))$copy_(q$view(c(rows, cols)))
  })
  tensor$mul_(gain)
  invisible(tensor)
}

#' Dirac initialization
#'
#' @param tensor A 3D, 4D, or 5D tensor.
#' @param groups Number of groups. Default 1.
#' @return tensor (modified in place).
#' @export
#' @examples
#' \donttest{
#' if (torch_is_installed()) {
#' 
#' w <- torch_empty(3, 16, 5, 5)
#' nn_init_dirac_(w)
#' 
#' 
#' }
#' }
nn_init_dirac_ <- function(tensor, groups = 1L) {
  dims <- tensor$size()
  if (length(dims) < 3 || length(dims) > 5)
    stop("Dirac init only supports 3D, 4D, and 5D tensors", call. = FALSE)
  with_no_grad(function() {
    tensor$zero_()
    min_dim <- min(dims[1] / groups, dims[2])
    for (g in seq_len(groups)) {
      for (d in seq_len(min_dim)) {
        idx <- switch(as.character(length(dims)),
          "3" = list(d + (g-1L) * (dims[1] / groups), d, dims[3] %/% 2L + 1L),
          "4" = list(d + (g-1L) * (dims[1] / groups), d, dims[3] %/% 2L + 1L, dims[4] %/% 2L + 1L),
          "5" = list(d + (g-1L) * (dims[1] / groups), d, dims[3] %/% 2L + 1L, dims[4] %/% 2L + 1L, dims[5] %/% 2L + 1L)
        )
        do.call(`[<-`, c(list(tensor), idx, list(1)))
      }
    }
  })
  invisible(tensor)
}

#' Sparse initialization
#'
#' @param tensor A 2D tensor.
#' @param sparsity Fraction of elements to be zero in each column.
#' @param std Standard deviation of the normal distribution. Default 0.01.
#' @return tensor (modified in place).
#' @export
#' @examples
#' \donttest{
#' if (torch_is_installed()) {
#' 
#' w <- torch_empty(3, 5)
#' nn_init_sparse_(w, sparsity = 0.1)
#' 
#' }
#' }
nn_init_sparse_ <- function(tensor, sparsity, std = 0.01) {
  dims <- tensor$size()
  if (length(dims) != 2)
    stop("Sparse init only supports 2D tensors", call. = FALSE)
  rows <- dims[1]
  cols <- dims[2]
  n_zeros <- ceiling(sparsity * rows)
  with_no_grad(function() {
    tensor$normal_(0, std)
    for (col in seq_len(cols)) {
      zero_idx <- sample.int(rows, n_zeros)
      for (zi in zero_idx) tensor[zi, col] <- 0
    }
  })
  invisible(tensor)
}

#' Define a custom autograd function
#'
#' @param forward Forward function.
#' @param backward Backward function.
#' @return An autograd function class.
#' @export
#' @examples
#' \donttest{
#' if (torch_is_installed()) {
#' 
#' exp2 <- autograd_function(
#'   forward = function(ctx, i) {
#'     result <- i$exp()
#'     ctx$save_for_backward(result = result)
#'     result
#'   },
#'   backward = function(ctx, grad_output) {
#'     list(i = grad_output * ctx$saved_variable$result)
#'   }
#' )
#' }
#' }
autograd_function <- function(forward, backward) {
  structure(list(forward = forward, backward = backward),
            class = "torch_autograd_function")
}

#' Compute gradients
#'
#' @param outputs A `torch_tensor` or list of tensors to differentiate.
#' @param inputs A `torch_tensor` or list of tensors to differentiate with
#'   respect to.
#' @param grad_outputs Optional list of gradients of outputs; defaults to
#'   ones for scalar outputs.
#' @param retain_graph Logical; if `TRUE` the computation graph is retained
#'   for a subsequent backward pass.
#' @param create_graph Logical; if `TRUE` construct a graph over the
#'   gradients themselves so higher-order derivatives can be taken.
#' @param allow_unused Logical; if `TRUE` inputs that do not contribute to
#'   outputs get `NULL` gradients instead of raising.
#' @return A list of gradient tensors, one per input.
#' @export
#' @examples
#' \donttest{
#' if (torch_is_installed()) {
#' w <- torch_tensor(0.5, requires_grad = TRUE)
#' b <- torch_tensor(0.9, requires_grad = TRUE)
#' x <- torch_tensor(runif(100))
#' y <- 2 * x + 1
#' loss <- ((y - (w * x + b))^2)$mean()
#'
#' o <- autograd_grad(loss, list(w, b))
#' o
#' }
#' }
autograd_grad <- function(outputs, inputs, grad_outputs = NULL,
                          retain_graph = FALSE, create_graph = FALSE,
                          allow_unused = FALSE) {
  if (!is.list(outputs)) outputs <- list(outputs)
  if (!is.list(inputs)) inputs <- list(inputs)
  if (!is.null(grad_outputs) && !is.list(grad_outputs)) {
    grad_outputs <- list(grad_outputs)
  }
  C_autograd_grad(outputs, inputs, grad_outputs,
                  as.logical(retain_graph),
                  as.logical(create_graph),
                  as.logical(allow_unused))
}

